const crypto = require('crypto');

const item = items[0].json;
const config = {
  merchantId: 'REPLACE_WITH_YOUR_MERCHANT_ID',
  hashKey: 'REPLACE_WITH_YOUR_HASH_KEY',
  hashIV: 'REPLACE_WITH_YOUR_HASH_IV',
  checkoutUrl: 'https://payment.ecpay.com.tw/Cashier/AioCheckOut/V5',
  returnUrl: 'https://erick303.app.n8n.cloud/webhook/ecpay-payment-callback',
  choosePayment: 'Credit',
  needExtraPaidInfo: 'Y',
  tradeDesc: 'TimeWaver Audio'
};

const requiredKeys = ['merchantId', 'hashKey', 'hashIV', 'returnUrl'];
const missing = requiredKeys.filter((key) => config[key].startsWith('REPLACE_'));
if (missing.length) {
  throw new Error(`Please replace config values first: ${missing.join(', ')}`);
}

const tradeDate = new Date().toLocaleString('sv-SE', {
  timeZone: 'Asia/Taipei',
  hour12: false
}).replace(' ', ' ').replace(/-/g, '/');

const params = {
  MerchantID: config.merchantId,
  MerchantTradeNo: item.order_no,
  MerchantTradeDate: tradeDate,
  PaymentType: 'aio',
  TotalAmount: String(item.trade_amt || '299'),
  TradeDesc: config.tradeDesc,
  ItemName: item.product_name,
  ReturnURL: config.returnUrl,
  ChoosePayment: config.choosePayment,
  NeedExtraPaidInfo: config.needExtraPaidInfo,
  CustomField1: item.buyer_name,
  CustomField2: item.buyer_email,
  CustomField3: item.buyer_phone,
  CustomField4: item.product_code,
  EncryptType: '1'
};

const sortedQuery = Object.keys(params)
  .sort((a, b) => a.localeCompare(b))
  .map((key) => `${key}=${params[key] ?? ''}`)
  .join('&');

const raw = `HashKey=${config.hashKey}&${sortedQuery}&HashIV=${config.hashIV}`;
const encoded = encodeURIComponent(raw)
  .replace(/%20/g, '+')
  .replace(/!/g, '%21')
  .replace(/\(/g, '%28')
  .replace(/\)/g, '%29')
  .replace(/\*/g, '%2a')
  .replace(/~/g, '%7e')
  .toLowerCase();

params.CheckMacValue = crypto
  .createHash('sha256')
  .update(encoded)
  .digest('hex')
  .toUpperCase();

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');

const hiddenInputs = Object.entries(params)
  .map(([key, value]) => `<input type="hidden" name="${escapeHtml(key)}" value="${escapeHtml(value)}" />`)
  .join('');

const checkoutHtml = `<!doctype html>
<html lang="zh-Hant">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>正在前往綠界付款</title>
</head>
<body>
  <p>正在前往綠界付款頁，請稍候...</p>
  <form id="ecpay-form" method="post" action="${escapeHtml(config.checkoutUrl)}" accept-charset="UTF-8">
    ${hiddenInputs}
  </form>
  <script>
    document.getElementById('ecpay-form').submit();
  </script>
</body>
</html>`;

return [{ json: { ...item, ecpay_params: params, checkout_html: checkoutHtml } }];

